import React from "react";
import { motion } from "framer-motion";
import "./../theme.css";

function Projects() {
  const projects = [
    { icon: "🏠", title: "Southlands Housing", description: "Modular housing blocks with solar integration." },
    { icon: "💧", title: "River Rehabilitation", description: "Expanded water pumps, lighting, and repairs." },
    { icon: "⛏️", title: "Gold Recovery Simulation", description: "Heap leach recovery with investor dashboards." }
  ];

  const containerVariants = {
    hidden: { opacity: 0 },
    show: { opacity: 1, transition: { staggerChildren: 0.3 } }
  };

  const cardVariants = {
    hidden: { opacity: 0, y: 30 },
    show: { opacity: 1, y: 0, transition: { duration: 0.8 } }
  };

  return (
    <motion.section
      style={{ padding: "40px", textAlign: "center" }}
      variants={containerVariants}
      initial="hidden"
      whileInView="show"
      viewport={{ once: true }}
    >
      <h1 style={{ color: "#004080", marginBottom: "20px" }}>Our Projects</h1>
      <div
        style={{
          display: "grid",
          gridTemplateColumns: "repeat(auto-fit, minmax(250px, 1fr))",
          gap: "20px",
          marginTop: "20px"
        }}
      >
        {projects.map((project, index) => (
          <motion.div
            key={index}
            variants={cardVariants}
            className="card"
          >
            <div className="icon-rotate">{project.icon}</div>
            <h2 style={{ color: "#004080" }}>{project.title}</h2>
            <p style={{ color: "#555" }}>{project.description}</p>
          </motion.div>
        ))}
      </div>
    </motion.section>
  );
}

export default Projects;
